import Foundation

struct APIResponse: Codable {
    let source: String
    let status: String
    let message: String?
}

enum NetworkError: LocalizedError {
    case invalidURL
    case invalidResponse
    case httpError(Int)
    case decodingError
    case underlying(Error)

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .invalidResponse:
            return "Invalid response"
        case .httpError(let code):
            return "HTTP error \(code)"
        case .decodingError:
            return "Failed to decode response"
        case .underlying(let error):
            return error.localizedDescription
        }
    }
}

final class APIClient {
    private let session: URLSession

    init() {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: configuration)
    }

    func fetchAPIStatus() async throws -> APIResponse {
        try await request(urlString: "https://api.example.com/status")
    }

    func fetchLegacyStatus() async throws -> APIResponse {
        try await request(urlString: "http://legacy.internal/status")
    }

    private func request(urlString: String) async throws -> APIResponse {
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }

        do {
            let (data, response) = try await session.data(from: url)

            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.invalidResponse
            }

            guard 200..<300 ~= httpResponse.statusCode else {
                throw NetworkError.httpError(httpResponse.statusCode)
            }

            do {
                return try JSONDecoder().decode(APIResponse.self, from: data)
            } catch {
                throw NetworkError.decodingError
            }
        } catch {
            throw NetworkError.underlying(error)
        }
    }
}

import Foundation

@MainActor
final class ContentViewModel: ObservableObject {
    @Published var apiStatus: String = "Not loaded"
    @Published var legacyStatus: String = "Not loaded"
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private let apiClient: APIClient

    init(apiClient: APIClient) {
        self.apiClient = apiClient
    }

    func load() {
        Task {
            isLoading = true
            errorMessage = nil

            async let apiResult = loadAPI()
            async let legacyResult = loadLegacy()

            _ = await (apiResult, legacyResult)

            isLoading = false
        }
    }

    private func loadAPI() async {
        do {
            let response = try await apiClient.fetchAPIStatus()
            apiStatus = "\(response.source): \(response.status)"
        } catch {
            apiStatus = "Failed"
            errorMessage = error.localizedDescription
        }
    }

    private func loadLegacy() async {
        do {
            let response = try await apiClient.fetchLegacyStatus()
            legacyStatus = "\(response.source): \(response.status)"
        } catch {
            legacyStatus = "Failed"
            errorMessage = error.localizedDescription
        }
    }
}

